// Reads and modifies CSV rows
fn modify_csv(input: &str) -> String {
  let mut rdr = csv::ReaderBuilder::new()
    .has_headers(true)
    .from_reader(input.as_bytes());

  let mut wtr = csv::WriterBuilder::new()
    .has_headers(true)
    .from_writer(vec![]);

  for result in rdr.deserialize() {
    let record: Vec<String> = result.unwrap();

    // Example modification: add a new field at the end with 'Processed'
    let mut new_record = record.clone(); 
    new_record.push("Processed".to_string());

    wtr.serialize(new_record)?;
  }

  String::from_utf8(wtr.into_inner()).unwrap()
}

// revised function
fn modify_csv(input: &str) -> Result<String, Box<dyn Error>> {
  let mut rdr = csv::ReaderBuilder::new()
    .has_headers(true)
    .from_reader(input.as_bytes());

  let mut wtr = csv::WriterBuilder::new()
    .has_headers(true)
    .from_writer(vec![]);

  for result in rdr.deserialize() {
    match result {
      Ok(record: Vec<String>) => {
        let new_record = record.clone();
        new_record.push("Processed".to_string());
        wtr.serialize(new_record)?;
      }
      Err(e) => { return Err(Box::new(e)) } 
    }
  }

  Ok(String::from_utf8(wtr.into_inner())?)
}
